/* eslint-disable @typescript-eslint/no-explicit-any */
import axios from 'axios';
import * as readline from 'readline';
import { getConfig } from './auth';
import { startSpinner } from '../utils/spinner';

const API_BASE_URL = process.env.HICKORY_API_URL || 'http://localhost:5000';

// ANSI color codes
const RESET = '\x1b[0m';
const BOLD = '\x1b[1m';
const DIM = '\x1b[2m';
const RED = '\x1b[31m';
const GREEN = '\x1b[32m';
const YELLOW = '\x1b[33m';
const BLUE = '\x1b[34m';
const MAGENTA = '\x1b[35m';
const CYAN = '\x1b[36m';
const GRAY = '\x1b[90m';

interface TicketDto {
  id: string;
  ticketNumber: string;
  title: string;
  description: string;
  status: string;
  priority: string;
  submitterId: string;
  submitterName: string;
  assignedToId?: string;
  assignedToName?: string;
  createdAt: string;
  updatedAt: string;
  closedAt?: string;
  resolutionNotes?: string;
  commentCount: number;
}

function getAuthHeader(): string | null {
  const config = getConfig();
  if (!config || !config.accessToken) {
    return null;
  }
  return `Bearer ${config.accessToken}`;
}

function requireAuth(): string {
  const authHeader = getAuthHeader();
  if (!authHeader) {
    console.error('Error: Not authenticated. Run "hickory login" first.');
    process.exit(1);
  }
  return authHeader;
}

function requireAgentRole(): void {
  const config = getConfig();
  if (!config || !config.user) {
    console.error('Error: Not authenticated. Run "hickory login" first.');
    process.exit(1);
  }
  if (config.user.role !== 'Agent' && config.user.role !== 'Administrator') {
    console.error('Error: This command requires Agent or Administrator role.');
    process.exit(1);
  }
}

function promptInput(question: string): Promise<string> {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });

  return new Promise((resolve) => {
    rl.question(question, (answer) => {
      rl.close();
      resolve(answer);
    });
  });
}

function getStatusColor(status: string): string {
  switch (status.toLowerCase()) {
    case 'open':
      return BLUE;
    case 'inprogress':
      return YELLOW;
    case 'resolved':
      return GREEN;
    case 'closed':
      return GRAY;
    case 'cancelled':
      return RED;
    default:
      return RESET;
  }
}

function getPriorityColor(priority: string): string {
  switch (priority.toLowerCase()) {
    case 'critical':
      return RED;
    case 'high':
      return MAGENTA;
    case 'medium':
      return YELLOW;
    case 'low':
      return CYAN;
    default:
      return RESET;
  }
}

function formatDate(dateString: string): string {
  const date = new Date(dateString);
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
  const diffDays = Math.floor(diffHours / 24);

  if (diffHours < 1) return '< 1h ago';
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 7) return `${diffDays}d ago`;

  return date.toLocaleDateString();
}

