    // Table header
    console.log(
      dim(`${'Ticket'.padEnd(12)} ${'Title'.padEnd(40)} ${'Status'.padEnd(12)} ${'Priority'.padEnd(10)} ${'Assigned'.padEnd(20)} ${'Age'.padEnd(10)}`)
    );
    console.log(dim('-'.repeat(120)));

