 83→function formatDate(dateString: string): string {
 84→  const date = new Date(dateString);
 85→  const now = new Date();
 86→  const diffMs = now.getTime() - date.getTime();
 87→  const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
 88→  const diffDays = Math.floor(diffHours / 24);
 89→
 90→  if (diffHours < 1) return '< 1h ago';
 91→  if (diffHours < 24) return `${diffHours}h ago`;
 92→  if (diffDays < 7) return `${diffDays}d ago`;
 93→  
 94→  return date.toLocaleDateString();
 95→}
