321→    spinner = startSpinner('Closing ticket...');
322→
323→    await axios.post(
324→      `${API_BASE_URL}/api/tickets/${ticket.id}/close`,
325→      { resolutionNotes },
326→      { headers: { Authorization: authHeader } }
327→    );
328→
329→    spinner.succeed(`Ticket ${bold(ticket.ticketNumber)} closed successfully`);
330→    console.log('\nResolution notes saved:');
331→    console.log(dim(resolutionNotes) + '\n');
332→  } catch (error: unknown) {
333→    const err = error as any;
334→    if (err.response?.status === 401) {
335→      console.error('\n' + errorColor('Error: Authentication failed. Please login again.'));
336→    } else if (err.response?.status === 403) {
337→      console.error('\n' + errorColor('Error: Access denied. This command requires Agent or Administrator role.'));
338→    } else if (err.response?.status === 404) {
339→      console.error('\n' + errorColor(`Error: Ticket ${ticketNumber} not found`));
340→    } else if (err.response?.status === 400) {
341→      const errors = err.response?.data?.errors;
342→      if (errors && errors.ResolutionNotes) {
343→        console.error('\n' + errorColor(`Error: ${errors.ResolutionNotes.join(', ')}`));
344→      } else {
345→        console.error('\n' + errorColor(`Error: ${err.response?.data?.title || err.message}`));
346→      }
347→    } else {
348→      console.error('\n' + errorColor(`Error closing ticket: ${err.response?.data?.title || err.message}`));
349→    }
350→    process.exit(1);
351→  }
352→}
